    "risk.open_5d": "Refletir na contingência 5D",
    "risk.open_schedule": "Ver cronograma 4D",
    "risk.owner_placeholder": "Pesquisar membros da equipa...",
    "risk.probability_high": "Alta",
    "risk.probability_low": "Baixa",
    "risk.probability_medium": "Média",
    "risk.probability_very_high": "Muito alta",
